import pytest

def group_by(items: list, key_fn) -> dict:
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result


class TestGroupBy:

    def test_happy_path_group_by_length(self):
        items = ["apple", "banana", "cherry", "date"]
        result = group_by(items, len)
        assert result == {5: ["apple"], 6: ["banana", "cherry"], 4: ["date"]}

    def test_happy_path_group_by_first_letter(self):
        items = ["apple", "banana", "cherry", "date", "avocado"]
        result = group_by(items, lambda x: x[0])
        assert result == {'a': ['apple', 'avocado'], 'b': ['banana'], 'c': ['cherry'], 'd': ['date']}

    def test_empty_list(self):
        items = []
        result = group_by(items, len)
        assert result == {}

    def test_empty_string_items(self):
        items = ["", "", ""]
        result = group_by(items, len)
        assert result == {0: ["", "", ""]}

    def test_mixed_types(self):
        items = [1, 2, "apple", "banana", 3.14]
        result = group_by(items, type)
        assert result == {
            int: [1, 2],
            str: ["apple", "banana"],
            float: [3.14]
        }

    def test_key_function_returns_none(self):
        items = [1, 2, 3]
        result = group_by(items, lambda x: None)
        assert result == {None: [1, 2, 3]}

    def test_key_function_returns_same_value_for_all(self):
        items = [1, 2, 3]
        result = group_by(items, lambda x: "same")
        assert result == {"same": [1, 2, 3]}

    def test_key_function_raises_exception(self):
        items = [1, 2, 3]
        def key_fn(x):
            if x == 2:
                raise ValueError("Key function error")
            return x

        with pytest.raises(ValueError, match="Key function error"):
            result = group_by(items, key_fn) # The exception is raised during the first call to key_fn

    def test_items_are_mutable(self):
        items = [[1], [2], [1]]
        result = group_by(items, lambda x: x[0])
        assert result == {1: [[1], [1]], 2: [[2]]}
        items[0].append(4)
        assert result == {1: [[1, 4], [1]], 2: [[2]]} # The result dictionary now reflects the change in the original list
